import { Vex } from '@vex_dev/sdk';
import { Mastra } from 'mastra';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY,
  policies: ['ferpa-student-data', 'coppa-minors']
});

const agentPipeline = Mastra.createAgent({
  workflow: async (input, context) => {
    // Vex middleware validates before each step
    const validatedInput = await vex.validate({
      data: input,
      context: { studentAge: context.user.age },
      rules: ['no-pii-leakage', 'age-appropriate']
    });

    const stepOutput = await workflowStep(validatedInput);
    return await vex.approve(stepOutput);
  }
});

import { VexGuard } from '@vex_dev/sdk';

const memoryGuard = new VexGuard({
  policyId: 'education-memory-freshness',
  checks: [
    'data-age < 24h',
    'parental-consent-active',
    'no-stale-grades'
  ]
});

// In Mastra knowledge retrieval
agent.on('memoryRetrieve', async (retrievedContext) => {
  const isSafe = await memoryGuard.check({
    context: retrievedContext,
    metadata: { studentId: 'STUDENT_123', accessLevel: 'tutor' }
  });

  if (!isSafe) {
    throw new Error('Stale or unauthorized student context blocked');
  }
  return retrievedContext;
});

const contentGuard = new VexGuard({
  policyId: 'coppa-content-safety',
  thresholds: { toxicity: 0.1, ageRating: 'G' }
});

// Mastra tool call interceptor
Mastra.intercept('toolCall', async (toolCall) => {
  const result = await toolCall.execute();

  const complianceCheck = await contentGuard.validate({
    content: result.output,
    audience: { minAge: 8, maxAge: 14 },
    category: 'education'
  });

  if (!complianceCheck.passed) {
    console.warn('Blocked inappropriate content:', complianceCheck.violations);
    return { safeContent: 'Content review required. Please ask your teacher.' };
  }

  return result;
});
